"use strict";(globalThis.webpackChunkbook=globalThis.webpackChunkbook||[]).push([[2322],{5049(o){o.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/physical-ai-textbook/docs/intro","label":"Physical AI & Humanoid Robotics","docId":"intro","unlisted":false},{"type":"category","label":"Module 1: The Robotic Nervous System (ROS 2)","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/physical-ai-textbook/docs/module-1-ros2/intro","label":"Introduction to ROS 2","docId":"module-1-ros2/intro","unlisted":false},{"type":"link","href":"/physical-ai-textbook/docs/module-1-ros2/nodes-and-topics","label":"ROS 2 Nodes and Topics","docId":"module-1-ros2/nodes-and-topics","unlisted":false}],"href":"/physical-ai-textbook/docs/category/module-1-the-robotic-nervous-system-ros-2"},{"type":"category","label":"Module 2: The Digital Twin (Gazebo & Unity)","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/physical-ai-textbook/docs/module-2-digital-twin/intro","label":"The Digital Twin: Gazebo & Unity","docId":"module-2-digital-twin/intro","unlisted":false},{"type":"link","href":"/physical-ai-textbook/docs/module-2-digital-twin/physics-simulation","label":"Gazebo Physics Simulation","docId":"module-2-digital-twin/physics-simulation","unlisted":false}],"href":"/physical-ai-textbook/docs/category/module-2-the-digital-twin-gazebo--unity"},{"type":"category","label":"Module 3: The AI-Robot Brain (NVIDIA Isaac)","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/physical-ai-textbook/docs/module-3-ai-robot-brain/intro","label":"The AI-Robot Brain: NVIDIA Isaac","docId":"module-3-ai-robot-brain/intro","unlisted":false},{"type":"link","href":"/physical-ai-textbook/docs/module-3-ai-robot-brain/photorealistic-simulation","label":"Isaac Sim: Photorealistic Simulation & Synthetic Data","docId":"module-3-ai-robot-brain/photorealistic-simulation","unlisted":false},{"type":"link","href":"/physical-ai-textbook/docs/module-3-ai-robot-brain/isaac-ros-vslam","label":"Isaac ROS & Visual SLAM (VSLAM)","docId":"module-3-ai-robot-brain/isaac-ros-vslam","unlisted":false}],"href":"/physical-ai-textbook/docs/category/module-3-the-ai-robot-brain-nvidia-isaac"},{"type":"category","label":"Module 4: Vision-Language-Action (VLA)","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/physical-ai-textbook/docs/module-4-vla/intro","label":"Vision-Language-Action (VLA)","docId":"module-4-vla/intro","unlisted":false},{"type":"link","href":"/physical-ai-textbook/docs/module-4-vla/humanoid-locomotion","label":"Humanoid Robot Kinematics & Locomotion","docId":"module-4-vla/humanoid-locomotion","unlisted":false},{"type":"link","href":"/physical-ai-textbook/docs/module-4-vla/voice-interface","label":"Voice Interface Implementation","docId":"module-4-vla/voice-interface","unlisted":false}],"href":"/physical-ai-textbook/docs/category/module-4-vision-language-action-vla"},{"type":"link","href":"/physical-ai-textbook/docs/chatbot-test","label":"Chatbot Test Page","docId":"chatbot-test","unlisted":false}]},"docs":{"chatbot-test":{"id":"chatbot-test","title":"Chatbot Test Page","description":"Test page for the Physical AI Textbook Chatbot","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Physical AI & Humanoid Robotics","description":"Welcome to the AI-native textbook for Physical AI & Humanoid Robotics. This course bridges the gap between digital intelligence and physical embodiment, teaching you how to design, simulate, and deploy humanoid robots capable of natural human interactions.","sidebar":"tutorialSidebar"},"module-1-ros2/intro":{"id":"module-1-ros2/intro","title":"Introduction to ROS 2","description":"Robot Operating System 2 (ROS 2) is the foundational middleware for modern robotics. In this module, you\'ll learn how ROS 2 enables communication between different components of a robotic system, forming the \\"nervous system\\" of your humanoid robot.","sidebar":"tutorialSidebar"},"module-1-ros2/nodes-and-topics":{"id":"module-1-ros2/nodes-and-topics","title":"ROS 2 Nodes and Topics","description":"Nodes and topics form the core communication model in ROS 2. In this lesson, you\'ll learn how to create nodes that publish and subscribe to topics, enabling different parts of your robotic system to exchange information.","sidebar":"tutorialSidebar"},"module-2-digital-twin/intro":{"id":"module-2-digital-twin/intro","title":"The Digital Twin: Gazebo & Unity","description":"A digital twin is a virtual representation of a physical system that mirrors its behavior in real-time. In this module, you\'ll learn to create digital twins of humanoid robots using Gazebo for physics simulation and Unity for high-fidelity visualization.","sidebar":"tutorialSidebar"},"module-2-digital-twin/physics-simulation":{"id":"module-2-digital-twin/physics-simulation","title":"Gazebo Physics Simulation","description":"Physics simulation is at the heart of creating realistic digital twins. Gazebo provides multiple physics engines and comprehensive simulation capabilities for testing robotic systems in virtual environments before deploying to real hardware.","sidebar":"tutorialSidebar"},"module-3-ai-robot-brain/intro":{"id":"module-3-ai-robot-brain/intro","title":"The AI-Robot Brain: NVIDIA Isaac","description":"NVIDIA Isaac is a comprehensive platform for AI-powered robotics that brings together simulation, perception, and AI training. In this module, you\'ll learn to use Isaac Sim for photorealistic simulation, Isaac ROS for hardware-accelerated perception, and Nav2 for intelligent navigation.","sidebar":"tutorialSidebar"},"module-3-ai-robot-brain/isaac-ros-vslam":{"id":"module-3-ai-robot-brain/isaac-ros-vslam","title":"Isaac ROS & Visual SLAM (VSLAM)","description":"Isaac ROS provides GPU-accelerated ROS 2 packages that run perception algorithms at real-time speeds on NVIDIA hardware. This lesson focuses on Visual SLAM for robot localization and Nav2 integration for autonomous navigation.","sidebar":"tutorialSidebar"},"module-3-ai-robot-brain/photorealistic-simulation":{"id":"module-3-ai-robot-brain/photorealistic-simulation","title":"Isaac Sim: Photorealistic Simulation & Synthetic Data","description":"NVIDIA Isaac Sim provides RTX-powered photorealistic simulation that bridges the gap between virtual training and real-world deployment. This lesson covers advanced Isaac Sim workflows for generating synthetic training data and reinforcement learning.","sidebar":"tutorialSidebar"},"module-4-vla/humanoid-locomotion":{"id":"module-4-vla/humanoid-locomotion","title":"Humanoid Robot Kinematics & Locomotion","description":"Humanoid robots are among the most mechanically complex systems in robotics. This lesson covers the fundamentals of bipedal kinematics, dynamic balance, and locomotion control needed to build walking robots.","sidebar":"tutorialSidebar"},"module-4-vla/intro":{"id":"module-4-vla/intro","title":"Vision-Language-Action (VLA)","description":"Vision-Language-Action (VLA) represents the convergence of large language models (LLMs), computer vision, and robotic control. In this module, you\'ll learn to build humanoid robots that understand natural language commands, perceive their environment visually, and execute complex actions autonomously.","sidebar":"tutorialSidebar"},"module-4-vla/voice-interface":{"id":"module-4-vla/voice-interface","title":"Voice Interface Implementation","description":"This lesson covers building a real-time voice interface for humanoid robots using OpenAI Whisper for speech recognition and integrating it with ROS 2 for command execution.","sidebar":"tutorialSidebar"}}}}')}}]);